@supported_compute_capability([90, 100, 103, 110, 120, 121])

def _heuristic_func_mm_bf16(
    suitable_backends: List[str],
    a: torch.Tensor,
    b: torch.Tensor,
    bias: Optional[torch.Tensor] = None,
    pdl: bool = False,
    out: Optional[torch.Tensor] = None,
    out_dtype: torch.dtype = torch.bfloat16,
    backend: Literal[
        "cudnn", "cutlass", "tgv", "cublaslt", "tinygemm", "auto"
    ] = "cudnn",
):
    heuristic_backends = []
    if bias is not None or pdl:
        # CUTLASS and cuBLASLt doesn't support bias/pdl, only TGV and cuDNN do
        if "tgv" in suitable_backends:
            heuristic_backends.append("tgv")
        if "cudnn" in suitable_backends:
            heuristic_backends.append("cudnn")
    else:
        if "cutlass" in suitable_backends:
            heuristic_backends.append("cutlass")
        if "tgv" in suitable_backends:
            heuristic_backends.append("tgv")
        if "cudnn" in suitable_backends:
            heuristic_backends.append("cudnn")
        if "cublaslt" in suitable_backends:
            heuristic_backends.append("cublaslt")

    if "tinygemm" in suitable_backends and out_dtype == torch.bfloat16:
        heuristic_backends.append("tinygemm")

    return heuristic_backends


@backend_requirement(

def _prepare_input_tensors_with_batches(
    self,
    inputs: List[torch.Tensor],
    tuning_config: TuningConfig,
) -> List[List[torch.Tensor]]:
    """Create multiple input copies to flush the L2 cache between profiling iterations."""
    if not tuning_config.use_cold_l2_cache:
        return [inputs]

    one_buffer_bytes = sum(
        input.numel() * input.element_size()
        if isinstance(input, torch.Tensor)
        else 0
        for input in inputs
    )
    if one_buffer_bytes <= 0:
        logger.debug(
            "[Autotuner] No tensor inputs or zero-sized tensors; falling back to single-batch profiling."
        )
        return [inputs]

    num_buffers = self._get_l2_cache_size_in_bytes() * 3 // one_buffer_bytes + 1
    num_buffers = min(num_buffers, self.repeat + 1)

    inputs_list = [inputs]
    for _ in range(num_buffers - 1):
        inputs_list.append(
            list(t.clone() if isinstance(t, torch.Tensor) else t for t in inputs)
        )

    logger.debug(
        f"[Autotuner] use_cold_l2_cache={tuning_config.use_cold_l2_cache}, use {num_buffers} different tensors for profiling"
    )
    return inputs_list

